#include <stdio.h>
#include <string.h>
int main() {
    char s[1000001];
    scanf("%s", s);
    int n = strlen(s);
    int i;
    for (i = 0; i < n; i++) {
        if (s[i] == '0') break;
    }
    if (i == n) {
        printf("0 %s", s);
    } else {
        printf("1");
        for (int j = 1; j < i; j++) printf("0");
        printf(" ");
        printf("1");
        for (int j = 1; j < n - i; j++) printf("0");
    }
    return 0;
}

